window.bookSummaryJSON = "<p>Mikhail Sholokhov’s groundbreaking epic novel gives a sweeping depiction of Russian life and culture in the early 20th century. In the same vein as <i>War and Peace</i>, by Leo Tolstoy, <i>And Quiet Flows the Don </i>gives listeners a glimpse into many aspects of Russian culture, and the choices a country makes when faced with war and destruction.</p>"; 
